{
  "permissions": {
    "allow": [
      "Bash(mkdir:*)",
      "Bash(npx prettier --write:*)",
      "Read(.claude/**)",
      "Write(.claude/**)",
      "Edit(.claude/**)",
      "Read(tasks/**)",
      "Write(tasks/**)",
      "Edit(tasks/**)",
      "Bash(git add:*)",
      "SlashCommand(/task:architect task-1764889273)",
      "Bash(yarn type-check:*)",
      "Bash(cat:*)",
      "Bash(npx tsc --noEmit)",
      "Bash(yarn lint:*)",
      "Bash(yarn test:*)",
      "Read(//Users/dmitry/.claude-code-docs/docs/**)"
    ],
    "deny": [
      "Read(.env)",
      "Read(../.env)"
    ],
    "ask": [],
    "defaultMode": "default"
  },
  "alwaysThinkingEnabled": true,
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Read",
        "hooks": [
          {
            "type": "command",
            "command": "~/.claude-code-docs/claude-docs-helper.sh hook-check"
          }
        ]
      }
    ]
  }
}

{
  "permissions": {
    "allow": [
      "Bash(mkdir:*)",
      "Bash(npx prettier:*)",
      "Bash(npx eslint:*)",
      "Bash(npx tsc:*)",
      "Read(**)",
      "Write(**)",
      "Edit(**)",
      "Bash(git add:*)"
    ],
    "deny": ["Read(.env)", "Read(../.env)"],
    "ask": []
  },
  "hooks": {
    "PostToolUse": [
      {
        "matcher": "Write|Edit",
        "hooks": [
          {
            "type": "command",
            "command": "npx prettier --write \"$CLAUDE_FILE_PATH\" 2>/dev/null || true"
          },
          {
            "type": "command",
            "command": "git add --ignore-errors \"$CLAUDE_FILE_PATH\" 2>/dev/null || true"
          }
        ]
      }
    ]
  }
}
